// @venom: browser
import React from "../jsx-runtime"; import type { ViewName } from "../data/types";
interface CommandProps { open:boolean; onClose:()=>void; onNavigate:(view:ViewName)=>void; onRefresh:()=>void; }
export default function CommandPalette({open,onClose,onNavigate,onRefresh}:CommandProps){ if(!open)return null; const commands=[["G O","Open command center",()=>onNavigate("overview")],["G I","Open incidents",()=>onNavigate("incidents")],["G A","Open asset inventory",()=>onNavigate("assets")],["G R","Open reports",()=>onNavigate("reports")],["R","Refresh protected intelligence",onRefresh]]; return <div className="modal-backdrop" onClick={onClose}><section className="command-modal" onClick={(event)=>event.stopPropagation()}><div className="command-search">⌕<input autofocus placeholder="Type a command…"/><button onClick={onClose}>esc</button></div><div className="command-list">{commands.map(command=><button onClick={()=>{command[2]();onClose();}}><kbd>{command[0]}</kbd><span>{command[1]}</span><b>↵</b></button>)}</div></section></div>; }
